UPDATE product SET description = '<p>Le Laryngoscope Avec Lames – Cullinan (Multi-Tailles) est conçu pour répondre aux exigences élevées des professionnels de santé dans le cadre de procédures intubatoires complexes. Fabriqué en acier inoxydable 304 de qualité supérieure, ce dispositif assure une biocompatibilité exceptionnelle et une robustesse à toute épreuve. L’ergonomie des manches et la conception interchangeable des lames offrent une flexibilité inégalée, permettant un usage atraumatique et précis lors des interventions médicales délicates.</p><p>La conception multifonctionnelle de cet instrument se distingue par un système d’attache sécurisée des lames, garantissant des conditions optimales de sécurité et de fiabilité pendant les procédures chirurgicales. Le choix des tailles, allant de 00 à 5, assure une adaptabilité optimale, satisfaisant les besoins spécifiques de différents patients tout en facilitant la tâche des cliniciens à travers des ajustements rapides et aisés.</p><p>Conforme aux normes CE, le laryngoscope dispose d’un procédé de stérilisation avancé à l''oxyde d''éthylène (EO), garantissant une désinfection complète et efficace pour une utilisation réitérée en milieu hospitalier. Ce produit est fourni dans un conditionnement en boîte individuelle pour une manutention aisée et une gestion efficace des stocks.</p><table class="min-w-full leading-normal"><thead><tr><th class="px-5 py-3 border-b-2 border-gray-300 bg-gray-50 text-left text-xs font-semibold text-gray-600 uppercase tracking-wider">Catégorie</th><th class="px-5 py-3 border-b-2 border-gray-300 bg-gray-50 text-left text-xs font-semibold text-gray-600 uppercase tracking-wider">Détails</th></tr></thead><tbody><tr><td class="px-5 py-5 border-b border-gray-300 bg-white text-sm">Matériau</td><td class="px-5 py-5 border-b border-gray-300 bg-white text-sm">Acier Inoxydable 304</td></tr><tr><td class="px-5 py-5 border-b border-gray-300 bg-white text-sm">Stérilisation</td><td class="px-5 py-5 border-b border-gray-300 bg-white text-sm">Oxyde d''éthylène (EO)</td></tr><tr><td class="px-5 py-5 border-b border-gray-300 bg-white text-sm">Conformité</td><td class="px-5 py-5 border-b border-gray-300 bg-white text-sm">CE</td></tr><tr><td class="px-5 py-5 border-b border-gray-300 bg-white text-sm">Usage Clinique</td><td class="px-5 py-5 border-b border-gray-300 bg-white text-sm">Professionnel médical</td></tr><tr><td class="px-5 py-5 border-b border-gray-300 bg-white text-sm">Caractéristiques</td><td class="px-5 py-5 border-b border-gray-300 bg-white text-sm">Interchangeabilité des lames, Taille multiple, Stérilisation EO</td></tr></tbody></table>', specifications = '{"Mat\u00e9riau": "Acier Inoxydable 304", "St\u00e9rilisation": "Oxyde d''\u00e9thyl\u00e8ne (EO)", "Conformit\u00e9": "CE", "Usage Clinique": "Professionnel m\u00e9dical", "Caract\u00e9ristiques": ["Interchangeabilit\u00e9 des lames", "Taille multiple", "St\u00e9rilisation EO"]}' WHERE id = 60;
UPDATE product SET description = '<div class="prose max-w-full p-4">
    <p class="mb-4">Le Kit Péridural Egemen, référence SKU TMT-EPIS18903, constitue une avancée significative dans l''exécution des blocages épiduraux en chirurgie. Conçu pour les praticiens cherchant l''excellence clinique, ce dispositif utilise du polycarbonate médical qui garantit une biocompatibilité exceptionnelle, minimisant ainsi le risque de réaction adverse chez les patients. La robustesse et la transparence du matériau facilitent la manipulation précise et sûre au cours des procédures médicales délicates.</p>
    <p class="mb-4">Chaque kit est minutieusement stérilisé à l''aide de l''oxyde d''éthylène (EO), assurant une asepsie totale indispensable pour réduire les risques d''infection nosocomiale. La certification CE 0120 atteste de la conformité aux normes de sécurité et de performance les plus exigeantes, garantissant une confiance totale dans l''utilisation clinique de chaque dispositif.</p>
    <p class="mb-4">Conçu spécifiquement pour les interventions chirurgicales requérant un bloc épidural, le Kit Péridural Egemen se distingue par son aiguille dotée d''une pointe atraumatique avec biseau gradué. Cette caractéristique minimise le traumatisme tissulaire et améliore le confort du patient tout en procurant une grande sensibilité tactile pour le praticien. L''ergonomie avancée de ce dispositif permet une précision et une stabilité accrues, assurant un positionnement optimal lors de l''insertion.</p>
</div>

