    </table>
</div>', specifications = '{"Mat\u00e9riau": "Ciseaux: Acier Inoxydable 304", "St\u00e9rilisation": "Compresses: Oxyde d''\u00e9thyl\u00e8ne (EO)", "Conformit\u00e9 CE / ISO": "Conforme aux normes CE", "Usage Clinique": "\u00c9quipements de premiers secours pour intervention d''urgence", "Caract\u00e9ristiques": "Couverture de survie 210 x 160 cm, sparadrap microporeux hypoallerg\u00e9nique"}' WHERE id = 10005;